// ─── AUTH SCREEN ─────────────────────────────────────────────────────────────
function AuthScreen({ onAuth }) {
  const [tab,    setTab]    = useState("login"); // "login" | "signup"
  const [email,  setEmail]  = useState("");
  const [pw,     setPw]     = useState("");
  const [name,   setName]   = useState("");
  const [err,    setErr]    = useState("");
  const [loading,setLoading]= useState(false);

  const inputStyle = {
    width:"100%", padding:"15px 16px", background:C.surface,
    border:`1px solid ${C.border}`, borderRadius:2, color:C.white,
    fontFamily:BC, fontSize:15, letterSpacing:0.5, marginBottom:12,
    outline:"none", transition:"border-color 0.15s",
  };

  async function handleSubmit() {
    setErr(""); setLoading(true);
    if (tab==="signup") {
      const { data, error } = await SB.auth.signUp({ email, password:pw });
      if (error) { setErr(error.message); setLoading(false); return; }
      if (data.user) {
        const { error:pe } = await SB.from("profiles").insert({ id:data.user.id, username:name });
        if (pe) { setErr(pe.message); setLoading(false); return; }
        onAuth(data.user, name);
      }
    } else {
      const { data, error } = await SB.auth.signInWithPassword({ email, password:pw });
      if (error) { setErr(error.message); setLoading(false); return; }
      // Fetch profile — if missing (failed signup), create it now
      let { data:prof } = await SB.from("profiles").select("username").eq("id",data.user.id).single();
      if (!prof) {
        const fallbackName = email.split("@")[0];
        await SB.from("profiles").insert({ id:data.user.id, username:fallbackName });
        prof = { username:fallbackName };
      }
      onAuth(data.user, prof.username);
    }
    setLoading(false);
  }

  return (
    <div style={{fontFamily:BC,background:C.bg,color:C.white,height:"100dvh",maxWidth:440,margin:"0 auto",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"0 28px",position:"relative"}}>
      <div style={NOISE}/>
      <div style={{position:"relative",zIndex:1,width:"100%"}}>
        <div style={{textAlign:"center",marginBottom:36}}>
          <img src={LOGO} alt="EKC" style={{width:120,height:120,objectFit:"contain",mixBlendMode:"screen",marginBottom:12,display:"block",margin:"0 auto 12px"}}/>
          <div style={{fontFamily:BB,fontSize:9,letterSpacing:0.8,color:C.muted}}>EKC BATTLE · UTRECHT '26</div>
        </div>

        {/* Tab switcher */}
        <div style={{display:"flex",gap:0,marginBottom:24,borderBottom:`1px solid ${C.border}`}}>
          {["login","signup"].map(t=>(
            <button key={t} onClick={()=>{setTab(t);setErr("");}} style={{
              flex:1,padding:"12px 0",background:"transparent",border:"none",
              borderBottom:`2px solid ${tab===t?C.white:"transparent"}`,
              color:tab===t?C.white:C.muted,fontFamily:BB,fontWeight:700,fontSize:16,letterSpacing:0.6,
              cursor:"pointer",transition:"all 0.15s",marginBottom:-1,
            }}>{t==="login"?"LOG IN":"SIGN UP"}</button>
          ))}
        </div>

        {tab==="signup" && (
          <input placeholder="Username" value={name} onChange={e=>setName(e.target.value)}
            style={inputStyle}/>
        )}
        <input placeholder="Email" type="email" value={email} onChange={e=>setEmail(e.target.value)}
          style={inputStyle}/>
        <input placeholder="Password" type="password" value={pw} onChange={e=>setPw(e.target.value)}
          style={inputStyle} onKeyDown={e=>e.key==="Enter"&&handleSubmit()}/>

        {err && <div style={{fontFamily:BC,fontWeight:500,fontSize:13,color:C.red,marginBottom:14,letterSpacing:0.5,lineHeight:1.4}}>{err}</div>}

        <BtnPrimary onClick={handleSubmit} style={{marginTop:4}}>
          {loading ? "···" : tab==="login"?"LOG IN":"CREATE ACCOUNT"}
        </BtnPrimary>
      </div>
    </div>
  );
}

// ─── STATS SCREEN ────────────────────────────────────────────────────────────
function StatsScreen({ user, username, onBack }) {
  const [matches,  setMatches]  = useState(null);
  const [attempts, setAttempts] = useState(null);

  useEffect(()=>{
    SB.from("match_results").select("*").eq("user_id",user.id).order("created_at",{ascending:false})
      .then(({data})=>setMatches(data||[]));
    SB.from("trick_attempts").select("trick,landed,competition").eq("user_id",user.id)
      .then(({data})=>setAttempts(data||[]));
  },[]);

  const DIVISIONS = [
    { key:"am_open", label:"AM OPEN" },
    { key:"open",    label:"PRO OPEN" },
  ];
  const DIFFICULTIES = ["easy","medium","hard"];
  const DIFF_LABELS  = { easy:"ROOKIE", medium:"AMATEUR", hard:"PRO" };

  // Build per-division match stats
  const matchStats = DIVISIONS.map(div=>{
    const divMatches = (matches||[]).filter(m=>m.competition===div.key);
    const byDiff = DIFFICULTIES.map(d=>{
      const sub = divMatches.filter(m=>m.difficulty===d);
      const w = sub.filter(m=>m.won).length;
      return { diff:d, wins:w, losses:sub.length-w, total:sub.length };
    }).filter(d=>d.total>0);
    return { ...div, total:divMatches.length, byDiff };
  }).filter(d=>d.total>0);

  // Build per-division trick stats
  const trickStats = {};
  (attempts||[]).forEach(a=>{
    const div = a.competition||"am_open";
    if (!trickStats[div]) trickStats[div]={};
    if (!trickStats[div][a.trick]) trickStats[div][a.trick]={land:0,miss:0};
    if (a.landed) trickStats[div][a.trick].land++;
    else trickStats[div][a.trick].miss++;
  });

  const trickDivisions = DIVISIONS.map(div=>{
    const stats = trickStats[div.key]||{};
    const list = Object.entries(stats)
      .map(([t,s])=>({ trick:t, rate:Math.round(s.land/(s.land+s.miss)*100), att:s.land+s.miss }))
      .sort((a,b)=>b.att-a.att);
    return { ...div, list };
  }).filter(d=>d.list.length>0);

  const root = {fontFamily:BC,background:C.bg,color:C.white,height:"100dvh",maxWidth:440,margin:"0 auto",display:"flex",flexDirection:"column",position:"relative",overflow:"hidden"};

  const TrickRow = ({trick,rate,att}) => {
    const col = rate>=70?C.green:rate>=40?C.yellow:C.red;
    return (
      <div style={{marginBottom:14}}>
        <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
          <div style={{fontFamily:BC,fontWeight:500,fontSize:13,color:C.sub,fontWeight:600,flex:1,paddingRight:12,lineHeight:1.3}}>{trick}</div>
          <div style={{fontFamily:BB,fontWeight:700,fontSize:16,letterSpacing:0.4,color:col,whiteSpace:"nowrap"}}>{rate}%</div>
        </div>
        <div style={{display:"flex",gap:4,alignItems:"center"}}>
          <div style={{flex:1,height:2,background:C.border}}>
            <div style={{height:2,background:col,width:`${rate}%`,transition:"width 0.4s ease"}}/>
          </div>
          <div style={{fontFamily:BC,fontWeight:500,fontSize:10,color:C.muted,letterSpacing:0.2,marginLeft:6}}>{att} tries</div>
        </div>
      </div>
    );
  };

  return (
    <div style={root}>
      <div style={NOISE}/>
      <div style={{position:"relative",zIndex:1,flex:1,display:"flex",flexDirection:"column",padding:"28px 24px",overflowY:"auto",WebkitOverflowScrolling:"touch"}}>
        <BackBtn onClick={onBack}/>

        <div style={{marginBottom:28}}>
          <div style={{fontFamily:BB,fontWeight:900,fontSize:38,letterSpacing:0.8,lineHeight:1,color:C.white}}>{username}</div>
          <div style={{fontFamily:BC,fontWeight:500,fontSize:12,color:C.muted,letterSpacing:0.6,marginTop:8,fontWeight:600}}>Training Stats</div>
        </div>

        <Div mb={24}/>

        {/* ── RECORD VS CPU ── */}
        <Label style={{marginBottom:20,letterSpacing:0.8}}>Record vs CPU</Label>
        {matches===null ? (
          <div style={{fontFamily:BC,fontWeight:500,fontSize:14,color:C.muted,marginBottom:28}}>Loading...</div>
        ) : matchStats.length===0 ? (
          <div style={{fontFamily:BC,fontWeight:500,fontSize:14,color:C.muted,marginBottom:28}}>No matches yet. Play vs CPU to see your stats.</div>
        ) : (
          matchStats.map(div=>(
            <div key={div.key} style={{marginBottom:28}}>
              {/* Division header */}
              <div style={{fontFamily:BB,fontWeight:700,fontSize:14,letterSpacing:0.8,color:C.white,marginBottom:14,borderLeft:`3px solid ${C.white}`,paddingLeft:12}}>
                {div.label}
              </div>
              {/* Per-difficulty rows */}
              {div.byDiff.map(d=>{
                const rate = Math.round(d.wins/d.total*100);
                const col  = rate>=60?C.green:rate>=40?C.yellow:C.red;
                return (
                  <div key={d.diff} style={{marginBottom:14}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:5}}>
                      <div style={{fontFamily:BB,fontSize:12,letterSpacing:0.8,color:C.muted}}>{DIFF_LABELS[d.diff]}</div>
                      <div style={{display:"flex",gap:16,alignItems:"baseline"}}>
                        <span style={{fontFamily:BB,fontSize:11,letterSpacing:0.5,color:C.green}}>{d.wins}W</span>
                        <span style={{fontFamily:BB,fontSize:11,letterSpacing:0.5,color:C.red}}>{d.losses}L</span>
                        <span style={{fontFamily:BB,fontWeight:700,fontSize:14,letterSpacing:0.4,color:col}}>{rate}%</span>
                      </div>
                    </div>
                    <div style={{height:2,background:C.border}}>
                      <div style={{height:2,background:col,width:`${rate}%`,transition:"width 0.5s ease"}}/>
                    </div>
                  </div>
                );
              })}
            </div>
          ))
        )}

        <Div mb={24}/>

        {/* ── LANDING RATE PER TRICK ── */}
        <Label style={{marginBottom:20,letterSpacing:0.8}}>Landing Rate per Trick</Label>
        {attempts===null ? (
          <div style={{fontFamily:BC,fontWeight:500,fontSize:14,color:C.muted}}>Loading...</div>
        ) : trickDivisions.length===0 ? (
          <div style={{fontFamily:BC,fontWeight:500,fontSize:14,color:C.muted}}>No trick data yet.</div>
        ) : (
          trickDivisions.map(div=>(
            <div key={div.key} style={{marginBottom:32}}>
              <div style={{fontFamily:BB,fontWeight:700,fontSize:14,letterSpacing:0.8,color:C.white,marginBottom:16,borderLeft:`3px solid ${C.white}`,paddingLeft:12}}>
                {div.label}
              </div>
              {div.list.map(t=><TrickRow key={t.trick} {...t}/>)}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

